{{
  (() => {
    const dados = _TempoResposta.data; // pega todos os registros
    if (!dados || dados.length === 0) {
      return "Nenhum dado encontrado para o período.";
    }

    // pega o último dia (data mais recente)
    const hoje = dados[dados.length - 1];
    // pega o dia com maior tempo médio de resposta
    const pico = _.maxBy(dados, "tempo_medio_resposta_min");

    const variacao = ((hoje.tempo_medio_resposta_min - pico.tempo_medio_resposta_min) / 
                      (pico.tempo_medio_resposta_min || 1)) * 100;

    if (variacao > 0) {
      return `Hoje (${hoje.dia}) o tempo médio de resposta aumentou ${variacao.toFixed(2)}% em relação ao pico (${pico.dia}).`;
    } else if (variacao < 0) {
      return `Hoje (${hoje.dia}) o tempo médio de resposta caiu ${Math.abs(variacao.toFixed(2))}% em relação ao pico (${pico.dia}).`;
    } else {
      return `Hoje (${hoje.dia}) está igual ao pico (${pico.dia}), sem variação.`;
    }
  })()
}}
